main(){

    int n,i,j,k,pom;

    scanf("%d",&n);

    int br = 0;

    for(i = 1; i <= n; i++){
        for(j = 1; j <= n; j++){
            k = i ^ j;
            if(i + j > k && i + k > j && k + j > i && i <= j && j <= k && k <= n){
                br++;
            }
        }
    }

    printf("%d",br);

