fn check(x: i32, y: i32, z: i32) -> bool {
  return x < y && y < z && x + y > z;
}

fn main() {
  let mut buffer = String::new();
  std::io::stdin().read_line(&mut buffer).unwrap();

  let n: i32 = buffer.trim().parse::<i32>().unwrap() + 1;

  let mut sum = 0;

  for x in 1..n {
    for y in 1..x {
      let z = x ^ y;
      if z < n &&  check(y, x, z) {
        sum += 1;
      }
    }
  }

  println!("{}", sum);
}
